                border-radius: 50%;
                margin-left: auto;
                margin-right: auto;
                margin-top: 6px
            }

            .christmas-garland .christmas-garland__item:nth-child(2n+1) .shape {
                -webkit-animation-name: flash-2;
                animation-name: flash-2;
                -webkit-animation-duration: .4s;
                animation-duration: .4s
