                animation-duration: 1.8s
            }

            .christmas-garland .christmas-garland__item:nth-child(3n+1) .shape {
                -webkit-animation-duration: 1.4s;
                animation-duration: 1.4s
            }

            .christmas-garland .christmas-garland__item:before {
