    <script>
        $(document).ready(function() {
            var $socialSlider = $('.social-slider');
            var $socialItems = $('.social-item');
            var socialSliderTop = $('body').offset().top;

            $(window).on('scroll', function() {
                var scrollPosition = $(window).scrollTop();

                if (scrollPosition >= socialSliderTop) {
                    var distanceFromTop = scrollPosition - socialSliderTop;
                    var leftPosition = -1 * distanceFromTop;
                    $socialItems.css('left', leftPosition + 'px');
                } else {
                    $socialItems.css('left', '0');
                }
            });
        });
    </script>

