    <!-- Signup Form Validation Script -->
    <script>
        $(document).ready(function() {
            // Real-time password confirmation validation
            $('#password_confirmation').on('keyup', function() {
                var password = $('#password').val();
                var confirmPassword = $(this).val();
                
                if (confirmPassword && password !== confirmPassword) {
                    $(this).addClass('is-invalid');
                    $(this).next('.invalid-feedback').remove();
                    $(this).after('<span class="invalid-feedback">Passwords do not match</span>');
                } else {
                    $(this).removeClass('is-invalid');
                    $(this).next('.invalid-feedback').remove();
                }
            });

            // Username validation (alphanumeric, underscore, hyphen only)
            $('#username').on('keyup', function() {
                var username = $(this).val();
                var pattern = /^[a-zA-Z0-9_-]+$/;
                
                if (username && !pattern.test(username)) {
                    $(this).addClass('is-invalid');
                    $(this).next('.invalid-feedback').remove();
                    $(this).after('<span class="invalid-feedback">Username can only contain letters, numbers, underscore, and hyphen</span>');
                } else {
                    $(this).removeClass('is-invalid');
                    $(this).next('.invalid-feedback').remove();
                }
            });

            // Name validation (letters and spaces only)
            $('#name').on('keyup', function() {
                var name = $(this).val();
                var pattern = /^[a-zA-Z\s\u00C0-\u017F]+$/;
                
                if (name && !pattern.test(name)) {
                    $(this).addClass('is-invalid');
                    $(this).next('.invalid-feedback').remove();
                    $(this).after('<span class="invalid-feedback">Name can only contain letters and spaces</span>');
                } else {
                    $(this).removeClass('is-invalid');
                    $(this).next('.invalid-feedback').remove();
                }
            });

            // Form submission validation
            $('form').on('submit', function(e) {
                var isValid = true;
                
                // Check if passwords match
                var password = $('#password').val();
                var confirmPassword = $('#password_confirmation').val();
                
                if (password !== confirmPassword) {
                    $('#password_confirmation').addClass('is-invalid');
                    $('#password_confirmation').next('.invalid-feedback').remove();
                    $('#password_confirmation').after('<span class="invalid-feedback">Passwords do not match</span>');
                    isValid = false;
                }
                
                // Check if terms are agreed
                if (!$('input[name="agree_terms"]').is(':checked')) {
                    $('input[name="agree_terms"]').addClass('is-invalid');
                    isValid = false;
                }
                
                if (!isValid) {
                    e.preventDefault();
                    return false;
                }
            });
        });
    </script>
